const raw = $input.first().json.output || $input.first().json.text || '';

let piiResults = [];

try {
  const clean = raw.replace(/```json|```/g, '').trim();
  piiResults = JSON.parse(clean);
} catch {
  const match = raw.match(/\[[\s\S]*\]/);
  if (match) {
    try { piiResults = JSON.parse(match[0]); } catch {}
  }
}

if (!piiResults || piiResults.length === 0) {
  return [{
    json: {
      error: 'No PII results found. Check the AI Agent output.',
      raw: raw.slice(0, 300),
    }
  }];
}

return piiResults.map((item, index) => ({
  json: {
    id:               index + 1,
    field_name:       item.field_name  || '',
    value:            item.value       || '',
    sensitivity:      item.sensitivity || '',
    confidence:       item.confidence  ?? null,
    location:         item.location    || '',
    context:          item.context     || '',
  }
}));

const raw = $input.first().json.output;

// ─── SECTION 1: DOCUMENT METADATA ───────────────────────────────────────────
function parseMetadata(text) {
  const extract = (field) => {
    const regex = new RegExp(`\\|\\s*${field}\\s*\\|\\s*([^|\\n]+?)\\s*\\|`, 'i');
    const match = text.match(regex);
    return match ? match[1].trim() : null;
  };

  const sourceRaw = extract('Source Type') || '';

  return {
    workflow_name:      extract('Workflow Name'),
    document_name:      extract('Document Name'),
    source_type:        sourceRaw.split('/')[0].trim(),
    processed_by:       sourceRaw.split('/')[1]?.trim() || 'LLM',
    scan_timestamp:     new Date().toISOString(),
    overall_risk_level: extract('Overall Risk Level'),
  };
}

// ─── SECTION 2: PII CATALOG ──────────────────────────────────────────────────
function parsePIICatalog(text) {
  const section = text.match(/## SECTION 2[\s\S]*?(?=## SECTION 3|$)/)?.[0] || '';
  const rows = section.split('\n').filter(line =>
    line.startsWith('|') &&
    !line.includes('---') &&
    !line.includes('field_name') &&
    !line.match(/^\|\s*#\s*\|/)
  );

  return rows.map((row, i) => {
    const cols = row.split('|').map(c => c.trim()).filter(Boolean);
    if (cols.length < 7) return null;
    return {
      id:          i + 1,
      field_name:  cols[1],
      value:       cols[2],
      sensitivity: cols[3],
      confidence:  parseFloat(cols[4]) || null,
      location:    cols[5],
      context:     cols[6],
    };
  }).filter(Boolean);
}

// ─── SECTION 3: RISK SUMMARY ─────────────────────────────────────────────────
function parseRiskSummary(text) {
  const section = text.match(/## SECTION 3[\s\S]*$/)?.[0] || '';
  const assessmentMatch = section.match(/Overall Risk Assessment:\s*(.+)/);
  const complianceMatch = section.match(/Compliance Flags:\s*(.+)/);

  return {
    overall_assessment: assessmentMatch ? assessmentMatch[1].trim() : null,
    // FIX: split by comma only when NOT inside parentheses
    compliance_flags: complianceMatch
      ? complianceMatch[1].split(/,(?![^(]*\))/).map(f => f.trim())
      : [],
  };
}

// ─── ASSEMBLE ────────────────────────────────────────────────────────────────
const metadata     = parseMetadata(raw);
const pii_catalog  = parsePIICatalog(raw);
const risk_summary = parseRiskSummary(raw);

// Recalculate counts from actual catalog
risk_summary.high_count   = pii_catalog.filter(p => p.sensitivity === 'HIGH').length;
risk_summary.medium_count = pii_catalog.filter(p => p.sensitivity === 'MEDIUM').length;
risk_summary.low_count    = pii_catalog.filter(p => p.sensitivity === 'LOW').length;
metadata.total_pii_found  = pii_catalog.length;

// ─── OUTPUT: one row per PII item (Excel-friendly) ───────────────────────────
const rows = pii_catalog.map(item => ({
  // Metadata columns repeated per row (for filtering in Excel)
  workflow_name:      metadata.workflow_name,
  document_name:      metadata.document_name,
  source_type:        metadata.source_type,
  scan_timestamp:     metadata.scan_timestamp,
  overall_risk_level: metadata.overall_risk_level,
  total_pii_found:    metadata.total_pii_found,
  // PII columns
  id:                 item.id,
  field_name:         item.field_name,
  value:              item.value,
  sensitivity:        item.sensitivity,
  confidence:         item.confidence,
  location:           item.location,
  context:            item.context,
  // Risk summary columns
  high_count:         risk_summary.high_count,
  medium_count:       risk_summary.medium_count,
  low_count:          risk_summary.low_count,
  compliance_flags:   risk_summary.compliance_flags.join(' | '),
  overall_assessment: risk_summary.overall_assessment,
}));

return rows.map(row => ({ json: row }));

